// Package finance provides cross-check tests that verify the Go port against
// reference data generated by the original Pascal code compiled with Free Pascal.
//
// The reference data is in legacy/reference-output/refdata.json, generated by
// legacy/testharness/refdata.pas.
package finance

import (
	"encoding/json"
	"math"
	"os"
	"testing"
	"time"

	"github.com/persense/persense-port/internal/dateutil"
	"github.com/persense/persense-port/internal/finance/interest"
	"github.com/persense/persense-port/internal/finance/mortgage"
	"github.com/persense/persense-port/internal/finance/presentvalue"
	"github.com/persense/persense-port/internal/types"
)

// refData holds the parsed reference JSON
type refData struct {
	JulianRoundtrip []struct {
		Year  int `json:"year"`
		Month int `json:"month"`
		Day   int `json:"day"`
		Jul   int64 `json:"julian"`
		RTD   int `json:"rt_d"`
		RTM   int `json:"rt_m"`
		RTY   int `json:"rt_y"`
	} `json:"julian_roundtrip"`

	Exxp []struct {
		Input  float64 `json:"input"`
		Output float64 `json:"output"`
	} `json:"exxp"`

	Lnn []struct {
		Input  float64 `json:"input"`
		Output float64 `json:"output"`
	} `json:"lnn"`

	Power []struct {
		X      float64 `json:"x"`
		N      float64 `json:"n"`
		Output float64 `json:"output"`
	} `json:"power"`

	Round2 []struct {
		Input  float64 `json:"input"`
		Output float64 `json:"output"`
	} `json:"round2"`

	YieldRateRoundtrip []struct {
		Rate      float64 `json:"rate"`
		PerYr     int     `json:"peryr"`
		Yield     float64 `json:"yield"`
		Roundtrip float64 `json:"roundtrip"`
	} `json:"yield_rate_roundtrip"`

	MortgageSummation []struct {
		Rate   float64 `json:"rate"`
		Years  float64 `json:"years"`
		Output float64 `json:"output"`
	} `json:"mortgage_summation"`

	MortgageCalc []struct {
		Price      float64 `json:"price"`
		Pct        float64 `json:"pct"`
		Years      int     `json:"years"`
		Rate       float64 `json:"rate"`
		Financed   float64 `json:"financed"`
		Summation  float64 `json:"summation"`
		Monthly    float64 `json:"monthly"`
	} `json:"mortgage_calc"`

	PVSumFormula []struct {
		Lnf    float64 `json:"lnf"`
		N      float64 `json:"n"`
		Output float64 `json:"output"`
	} `json:"pv_sumformula"`

	YearsDif []struct {
		From     string  `json:"from"`
		To       string  `json:"to"`
		Basis360 float64 `json:"basis360"`
		Basis365 float64 `json:"basis365"`
	} `json:"yearsdif"`
}

func loadRefData(t *testing.T) *refData {
	t.Helper()
	// Try multiple paths since tests run from different directories
	paths := []string{
		"../../legacy/reference-output/refdata.json",
		"../legacy/reference-output/refdata.json",
		"legacy/reference-output/refdata.json",
	}
	var data []byte
	var err error
	for _, p := range paths {
		data, err = os.ReadFile(p)
		if err == nil {
			break
		}
	}
	if err != nil {
		t.Fatalf("cannot read refdata.json: %v (tried %v)", err, paths)
	}
	var ref refData
	if err := json.Unmarshal(data, &ref); err != nil {
		t.Fatalf("cannot parse refdata.json: %v", err)
	}
	return &ref
}

func assertClose(t *testing.T, label string, got, want, tol float64) {
	t.Helper()
	diff := math.Abs(got - want)
	if want != 0 {
		relErr := diff / math.Abs(want)
		if relErr > tol && diff > 1e-12 {
			t.Errorf("%s: got %.15g, want %.15g (relErr=%.2e)", label, got, want, relErr)
		}
	} else if diff > tol {
		t.Errorf("%s: got %.15g, want 0", label, got)
	}
}

// --- Cross-check tests ---

func TestCrossCheckJulian(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.JulianRoundtrip {
		month := tc.Month
		day := tc.Day
		if month == 0 { month = 1 }
		if day == 0 { day = 1 }
		d := types.NewDateRec(tc.Year, time.Month(month), day)
		j := dateutil.Julian(d)
		if j != tc.Jul {
			t.Errorf("Julian(%d-%02d-%02d): got %d, pascal %d", tc.Year, month, day, j, tc.Jul)
		}
		// Round trip
		rt, err := dateutil.MDY(j)
		if err != nil {
			t.Errorf("MDY(%d) error: %v", j, err)
			continue
		}
		if rt.Time.Day() != tc.RTD || int(rt.Time.Month()) != tc.RTM || rt.Time.Year() != tc.RTY {
			t.Errorf("MDY(%d): got %d-%02d-%02d, pascal %d-%02d-%02d",
				j, rt.Time.Year(), rt.Time.Month(), rt.Time.Day(), tc.RTY, tc.RTM, tc.RTD)
		}
	}
}

func TestCrossCheckExxp(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.Exxp {
		got, err := interest.Exxp(tc.Input)
		if err != nil {
			t.Errorf("Exxp(%g) error: %v", tc.Input, err)
			continue
		}
		assertClose(t, "Exxp("+formatFloat(tc.Input)+")", got, tc.Output, 1e-10)
	}
}

