func TestCrossCheckRound2(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.Round2 {
		got := interest.Round2(tc.Input)
		if got != tc.Output {
			t.Errorf("Round2(%g): got %g, pascal %g", tc.Input, got, tc.Output)
		}
	}
}

func TestCrossCheckYieldRate(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.YieldRateRoundtrip {
		y, err := interest.YieldFromRate(tc.Rate, byte(tc.PerYr), 365.25)
		if err != nil {
			t.Errorf("YieldFromRate(%g, %d) error: %v", tc.Rate, tc.PerYr, err)
			continue
		}
		assertClose(t, "YieldFromRate("+formatFloat(tc.Rate)+")", y, tc.Yield, 1e-10)

		r, err := interest.RateFromYield(y, byte(tc.PerYr), 365.25)
		if err != nil {
			t.Errorf("RateFromYield error: %v", err)
			continue
		}
		assertClose(t, "RateFromYield roundtrip", r, tc.Rate, 1e-10)
	}
}

