func TestCrossCheckMortgageCalc(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.MortgageCalc {
		m := mortgage.MtgLine{
			PriceStatus: types.InOutInput,
			Price:       tc.Price,
			PctStatus:   types.InOutInput,
			Pct:         tc.Pct,
			YearsStatus: types.InOutInput,
			Years:       tc.Years,
			RateStatus:  types.InOutInput,
			Rate:        tc.Rate,
			TaxStatus:   types.InOutInput,
			Tax:         0,
			BalloonStat: types.BalloonBlank,
		}
		result := mortgage.Calc(m)
		if result.Err != nil {
			t.Errorf("Calc(price=%g,pct=%g,yrs=%d,rate=%g) error: %v",
				tc.Price, tc.Pct, tc.Years, tc.Rate, result.Err)
			continue
		}
		assertClose(t, "financed", result.Line.Financed, tc.Financed, 1e-10)
		assertClose(t, "monthly", result.Line.Monthly, tc.Monthly, 1e-10)
	}
}

