func TestCrossCheckYearsDif(t *testing.T) {
	ref := loadRefData(t)
	for _, tc := range ref.YearsDif {
		from := parseDate(t, tc.From)
		to := parseDate(t, tc.To)

		got360 := dateutil.YearsDif(to, from, types.Basis360, 1.0/365.25, false)
		assertClose(t, "YearsDif360("+tc.From+"→"+tc.To+")", got360, tc.Basis360, 1e-10)

		got365 := dateutil.YearsDif(to, from, types.Basis365, 1.0/365.25, false)
		// YearsDif365 involves Julian() which chains multiple integer and float ops.
		// Pascal real vs Go float64 accumulate differently at ~1e-8 level.
		assertClose(t, "YearsDif365("+tc.From+"→"+tc.To+")", got365, tc.Basis365, 1e-7)
	}
}

// --- helpers ---

func parseDate(t *testing.T, s string) types.DateRec {
	t.Helper()
	d, err := time.Parse("2006-01-02", s)
	if err != nil {
		t.Fatalf("bad date %q: %v", s, err)
	}
	return types.NewDateRec(d.Year(), d.Month(), d.Day())
}

func formatFloat(f float64) string {
	if f == float64(int64(f)) {
		return string(rune(int64(f) + '0'))
	}
	return ""
}
